creationInfo:
{%- if info.agency_id %}
  {{ info.agency_id }}
{%- endif %}
{%- if info.agency_uri %}
  {{ info.agency_uri }}
{%- endif %}
{%- if info.author %}
  {{ info.author }}
{%- endif %}
{%- if info.author_uri %}
  {{ info.author_uri }}
{%- endif %}
{%- if info.creation_time %}
  {{ info.creation_time }}
{%- endif %}
{%- if info.modification_time %}
  {{ info.modification_time }}
{%- endif %}
{%- if info.version %}
  {{ info.version }}
{%- endif %}

seiscomp.EventParameters:
{%- for event in jquake %}
  {%- for pick in event.pick %}


        {{ pick.time.value }}
      {%- if pick.time.lower_uncertainty %}
        {{ pick.time.lower_uncertainty }}
      {%- endif %}
      {%- if pick.time.upper_uncertainty %}
        {{ pick.time.upper_uncertainty }}
      {%- endif %}

      {{ waveform_id(pick.waveform_id) }}
    {%- if pick.filter_id %}
      {{ pick.filter_id | remove_resource_prefix }}
    {%- endif %}
    {%- if pick.method_id %}
      {{ pick.method_id | remove_resource_prefix }}
    {%- endif %}
      {{ pick.phase_hint }}
      {{ pick.evaluation_mode }}
    {%- if pick.evaluation_status %}
      {{ pick.evaluation_status }}
    {%- endif %}
    {%- if pick.creation_info %}
      {{ creation_info(pick.creation_info) }}
    {%- endif %}

  {%- endfor %}

{%- if event.amplitude %}
  {%- for amplitude in event.amplitude  %}

      {{ amplitude.type }}

        {{ amplitude.generic_amplitude.value }}


        {{ amplitude.time_window.reference }}
        {{ amplitude.time_window.begin }}
        {{ amplitude.time_window.end }}

      {{ amplitude.snr }}
      {{ amplitude.pick_id | remove_resource_prefix }}
      {{ waveform_id(amplitude.waveform_id) }}
    {%- if amplitude.creation_info %}
      {{ creation_info(amplitude.creation_info) }}
    {%- endif %}

  {%- endfor  %}
{%- endif %}

  {%- for origin in event.origin %}


        {{ origin.time.value }}
        {{ origin.time.uncertainty }}


        {{ real_quantity(origin.latitude) }}


        {{ real_quantity(origin.longitude) }}


        {{ origin.depth.value / 1000 }}
      {% if origin.depth.uncertainty %}
        {{ origin.depth.uncertainty / 1000 }}
      {% endif %}

    {%- if origin.method_id %}
      {{ origin.method_id | remove_resource_prefix }}
    {%- endif %}
    {%- if origin.earth_model_id %}
      {{ origin.earth_model_id | remove_resource_prefix }}
    {%- endif %}
    {%- if origin.quality %}

      {%- if origin.quality.associated_phase_count %}
        {{ origin.quality.associated_phase_count }}
      {%- endif %}
      {%- if origin.quality.used_phase_count %}
        {{ origin.quality.used_phase_count }}
      {%- endif %}
      {%- if origin.quality.associated_station_count %}
        {{ origin.quality.associated_station_count }}
      {%- endif %}
      {%- if origin.quality.used_station_count %}
        {{ origin.quality.used_station_count }}
      {%- endif %}
      {%- if origin.quality.standard_error %}
        {{ origin.quality.standard_error }}
      {%- endif %}
      {%- if origin.quality.azimuthal_gap %}
        {{ origin.quality.azimuthal_gap }}
      {%- endif %}
      {%- if origin.quality.maximum_distance %}
        {{ origin.quality.maximum_distance }}
      {%- endif %}
      {%- if origin.quality.minimum_distance %}
        {{ origin.quality.minimum_distance }}
      {%- endif %}
      {%- if origin.quality.median_distance %}
        {{ origin.quality.median_distance }}
      {%- endif %}

    {%- endif %}
      {{ origin.evaluation_mode }}
    {%- if origin.evaluation_status %}
      {{ origin.evaluation_status }}
    {%- endif %}
    {%- if origin.creation_info %}
      {{ creation_info(origin.creation_info) }}
    {%- endif %}

  {%- if origin.arrival %}
    {%- for arrival in origin.arrival %}

        {{ arrival.pick_id | remove_resource_prefix }}
        {{ arrival.phase }}
        {{ arrival.azimuth }}
        {{ arrival.distance }}
        {{ arrival.time_residual }}
        {% if arrival.time_weight == 0 %}false{% else %}true{% endif %}
        {{ arrival.time_weight }}
      {% if arrival.creation_info %}
        {{ creation_info(arrival.creation_info) }}
      {% endif %}

    {%- endfor %}
  {%- endif %}

{%- if event.station_magnitude %}
  {%- for station_magnitude in event.station_magnitude %}
    {%- if station_magnitude.origin_id == origin.public_id %}


          {{ station_magnitude.mag.value }}

        {{ station_magnitude.type }}
        {{ station_magnitude.amplitude_id | remove_resource_prefix }}
        {{ waveform_id(station_magnitude.waveform_id) }}
      {%- if station_magnitude.creation_info %}
        {{ creation_info(station_magnitude.creation_info) }}
      {%- endif %}

    {%- endif %}
  {%- endfor %}
{%- endif %}

{%- if event.magnitude %}
  {%- for magnitude in event.magnitude %}
    {%- if magnitude.origin_id == origin.public_id %}


          {{ real_quantity(magnitude.mag) }}

        {{ magnitude.type }}
      {%- if magnitude.origin_id %}
        {{ magnitude.origin_id | remove_resource_prefix }}
      {%- endif %}
      {%- if magnitude.method_id %}
        {{ magnitude.method_id | remove_resource_prefix }}
      {%- endif %}
      {%- if magnitude.station_count %}
        {{ magnitude.station_count }}
      {%- endif %}
      {%- if magnitude.creation_info %}
        {{ creation_info(magnitude.creation_info) }}
      {%- endif %}
    {%- if magnitude.station_magnitude_contribution %}
      {%- for station_magnitude_contribution in magnitude.station_magnitude_contribution %}

          {{ station_magnitude_contribution.station_magnitude_id | remove_resource_prefix }}
        {%- if station_magnitude_contribution.residual %}
          {{ station_magnitude_contribution.residual }}
        {%- endif %}
        {%- if station_magnitude_contribution.weight %}
          {{ station_magnitude_contribution.weight }}
        {%- endif %}

      {%- endfor %}
    {%- endif %}

    {%- endif %}
  {%- endfor %}
{%- endif %}



  {%- endfor %}


    {%- if event.preferred_origin_id %}
      {{ event.preferred_origin_id | remove_resource_prefix }}
    {%- endif %}
    {%- if event.preferred_magnitude_id %}
      {{ event.preferred_magnitude_id | remove_resource_prefix }}
    {%- endif %}
    {%- if event.type %}
      {{ event.type | sc3ml_type }}
    {%- endif %}
    {%- if event.type_certainty %}
      {{ event.type_certainty }}
    {%- endif %}
    {%- if event.creation_info %}
      {{ creation_info(event.creation_info) }}
    {%- endif %}
  {%- if event.description %}
    {%- for description in event.description %}

      {%- for key, value in description.iteritems() %}
        <{{ key }}>{{ value }}</{{ key }}>
      {%- endfor %}

    {%- endfor %}
  {%- endif %}
    {%- if event.comment %}
      {{ event.comment }}
    {%- endif %}
    {%- for origin in event.origin %}
      {{ origin.public_id | remove_resource_prefix }}
    {%- endfor %}

{%- endfor %}
